import java.util.*;
import java.lang.*;
import java.io.*;

class Codechef {
    public static void main (String[] args) throws java.lang.Exception {
        Scanner scanner = new Scanner(System.in); // Scanner for input
        int t = scanner.nextInt(); // Read number of test cases

        while (t-- > 0) {
            int n = scanner.nextInt(); // Read the value of n
            long ans = 0;
            ans += n; // First step to right most light
            ans += n; // Second step to left most light
            ans += (1L * n * (n - 1)) / 2; // From now it is n-1 + n-2 + ... + 1
            System.out.println(ans); // Output the result
        }

        scanner.close(); // Close the scanner
    }
}
